import React, { useState } from "react";
import axios from "axios";
import { useNavigate } from "react-router-dom";

function LoginScreen() {
  const [isRegister, setIsRegister] = useState(false);
  const [name, setName] = useState("");
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");

  const navigate = useNavigate();

  const submitHandler = async (e) => {
    e.preventDefault();

    try {
      if (isRegister) {
        await axios.post("http://localhost:5000/api/users/register", {
          name,
          email,
          password,
        });
        alert("Registration Successful");
        setIsRegister(false);
      } else {
        const { data } = await axios.post(
          "http://localhost:5000/api/users/login",
          { email, password }
        );
        localStorage.setItem("userInfo", JSON.stringify(data));
        navigate("/products");
      }
    } catch (error) {
      alert(error.response?.data?.message || "Error occurred");
    }
  };

  return (
    <div style={containerStyle}>
      <h1 style={logoStyle}> Welcome to SmartCart</h1>
      <p style={{ color: "#aaa", marginBottom: "30px" }}>
        Sign in to <b>continue</b>your Shopping
      </p>

      <form onSubmit={submitHandler} style={cardStyle}>
        {isRegister && (
          <>
            <label style={labelStyle}>FULL NAME</label>
            <input
              type="text"
              placeholder="Enter your name"
              value={name}
              onChange={(e) => setName(e.target.value)}
              required
              style={inputStyle}
            />
          </>
        )}

        <label style={labelStyle}>EMAIL ADDRESS</label>
        <input
          type="email"
          placeholder="name@example.com"
          value={email}
          onChange={(e) => setEmail(e.target.value)}
          required
          style={inputStyle}
        />

        <div style={{ display: "flex", justifyContent: "space-between" }}>
          <label style={labelStyle}>PASSWORD</label>
          {!isRegister && (
            <span style={{ color: "#ff4da6", fontSize: "13px" }}>
              FORGOT?
            </span>
          )}
        </div>

        <input
          type="password"
          placeholder="••••••••"
          value={password}
          onChange={(e) => setPassword(e.target.value)}
          required
          style={inputStyle}
        />

        <button type="submit" style={buttonStyle}>
          {isRegister ? "REGISTER →" : "Login to Smartcart →"}
        </button>
      </form>

      <p style={{ marginTop: "25px", color: "#aaa" }}>
        {isRegister ? "Already have an account?" : "NEW TO SMARTCART?"}
        <span
          onClick={() => setIsRegister(!isRegister)}
          style={{
            color: "#00e5ff",
            marginLeft: "8px",
            cursor: "pointer",
            fontWeight: "bold",
          }}
        >
          {isRegister ? "Login Now" : "Register Now"}
        </span>
      </p>
    </div>
  );
}

const containerStyle = {
  minHeight: "100vh",
  display: "flex",
  flexDirection: "column",
  alignItems: "center",
  justifyContent: "center",
  background: "linear-gradient(135deg, #0f2027, #203a43, #2c5364)",
  color: "#fff",
  textAlign: "center",
};

const logoStyle = {
  fontSize: "48px",
  fontWeight: "bold",
  background: "linear-gradient(90deg, #00e5ff, #ff4da6)",
  WebkitBackgroundClip: "text",
  WebkitTextFillColor: "transparent",
  marginBottom: "10px",
};

const cardStyle = {
  width: "380px",
  padding: "35px",
  borderRadius: "25px",
  backdropFilter: "blur(20px)",
  background: "rgba(255,255,255,0.08)",
  boxShadow: "0 0 40px rgba(0,0,0,0.4)",
  textAlign: "left",
};

const labelStyle = {
  fontSize: "12px",
  letterSpacing: "2px",
  color: "#ccc",
};

const inputStyle = {
  width: "100%",
  padding: "14px",
  marginTop: "8px",
  marginBottom: "18px",
  borderRadius: "15px",
  border: "1px solid rgba(255,255,255,0.2)",
  background: "rgba(255,255,255,0.1)",
  color: "#fff",
  outline: "none",
};

const buttonStyle = {
  width: "100%",
  padding: "14px",
  borderRadius: "30px",
  border: "none",
  background: "linear-gradient(90deg, #00e5ff, #ff4da6)",
  color: "#fff",
  fontWeight: "bold",
  cursor: "pointer",
  fontSize: "16px",
  marginTop: "10px",
};

export default LoginScreen;
